const raw = ($json.content || []).find(b => b.type === 'text')?.text || '';

const clean = raw.trim().startsWith('```')
  ? raw.trim().replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '').trim()
  : raw.trim();

const productId   = $('Webhook Trigger').first().json.body.product_id;
const productSlug = $('Build Claude Request Body').first().json.productSlug;

return [{ json: { html: clean, productId, productSlug } }];

const productId   = $('Parse HTML Output').item.json.productId;
const productSlug = $('Parse HTML Output').item.json.productSlug;

const specItems = $('Fetch Product Spec').all();
const specRaw = specItems.length > 0 ? specItems[0].json : [];
const product = Array.isArray(specRaw) ? (specRaw[0] || {}) : specRaw;

const title = product.name || product.title || 'Ebook';
const productType = (product.type || '').replace(/_/g, ' ');

const supabaseUrl = 'https://illcsxpidmluhdwgygwf.supabase.co';
const pdfUrl  = supabaseUrl + '/storage/v1/object/public/templates/ebooks/' + productId + '/' + productSlug + '.pdf';
const htmlUrl = supabaseUrl + '/storage/v1/object/public/templates/ebooks/' + productId + '/' + productSlug + '.html';

const html = '<div style=\"max-width:600px;margin:0 auto;font-family:Arial,sans-serif;color:#333;\">'
  + '<div style=\"background:#0A0A0A;padding:24px;text-align:center;\">'
  + '<span style=\"color:#C8F53A;font-size:18px;letter-spacing:3px;font-weight:bold;\">CIPHER STUDIO</span>'
  + '</div>'
  + '<div style=\"padding:24px;\">'
  + '<h2 style=\"margin:0 0 8px;font-size:20px;color:#0A0A0A;\">' + title + '</h2>'
  + '<p style=\"color:#666;margin:0 0 20px;font-size:14px;\">Your ebook has been designed and is ready for review.</p>'
  + '<table style=\"width:100%;margin:0 0 20px;\">'
  + '<tr><td style=\"padding:8px 0;font-size:14px;color:#888;\">Type</td><td style=\"padding:8px 0;font-size:14px;color:#333;\">' + productType + '</td></tr>'
  + '<tr><td style=\"padding:8px 0;font-size:14px;color:#888;\">Status</td><td style=\"padding:8px 0;font-size:14px;color:#333;\">Ready for review</td></tr>'
  + '</table>'
  + '<a href=\"' + pdfUrl + '\" style=\"display:block;background:#C8F53A;color:#0A0A0A;text-align:center;padding:14px;font-size:14px;font-weight:bold;text-decoration:none;border-radius:4px;margin:0 0 12px;\">Download PDF</a>'
  + '<a href=\"' + htmlUrl + '\" style=\"display:block;background:#1C1C1C;color:#C8F53A;text-align:center;padding:14px;font-size:14px;font-weight:bold;text-decoration:none;border-radius:4px;\">Preview HTML</a>'
  + '</div>'
  + '<div style=\"padding:16px 24px;border-top:1px solid #eee;text-align:center;\">'
  + '<span style=\"font-size:11px;color:#aaa;\">Cipher Studio LLC \u00b7 Automated notification</span>'
  + '</div>'
  + '</div>';

return [{ json: {
  subject: 'Ebook Ready: ' + title,
  html,
  pdfUrl,
  htmlUrl,
  productId
} }];
